/**
 * Migration: Add isOverride, overrideNote, isAutoGenerated to transaction_payout_items
 * Run: node scripts/migrate-payout-override.mjs
 */
import { createConnection } from "mysql2/promise";

const dbUrl = process.env.DATABASE_URL;
if (!dbUrl) {
  console.error("DATABASE_URL not set");
  process.exit(1);
}

const conn = await createConnection(dbUrl);

try {
  // Check if columns already exist
  const [cols] = await conn.execute(
    `SELECT COLUMN_NAME FROM INFORMATION_SCHEMA.COLUMNS 
     WHERE TABLE_NAME = 'transaction_payout_items' 
     AND COLUMN_NAME IN ('isOverride', 'overrideNote', 'isAutoGenerated')`
  );
  const existing = cols.map((c) => c.COLUMN_NAME);

  if (!existing.includes("isOverride")) {
    await conn.execute(
      `ALTER TABLE transaction_payout_items ADD COLUMN isOverride BOOLEAN NOT NULL DEFAULT FALSE`
    );
    console.log("Added isOverride column");
  }
  if (!existing.includes("overrideNote")) {
    await conn.execute(
      `ALTER TABLE transaction_payout_items ADD COLUMN overrideNote TEXT`
    );
    console.log("Added overrideNote column");
  }
  if (!existing.includes("isAutoGenerated")) {
    await conn.execute(
      `ALTER TABLE transaction_payout_items ADD COLUMN isAutoGenerated BOOLEAN NOT NULL DEFAULT FALSE`
    );
    console.log("Added isAutoGenerated column");
  }
  console.log("Migration complete.");
} finally {
  await conn.end();
}
